<?php
 namespace WPAICG\AIForms; use WPAICG\AIForms\Admin\AIPKit_AI_Form_Admin_Setup; use WPAICG\AIForms\Frontend\AIPKit_AI_Form_Shortcode; use WPAICG\AIForms\Core\AIPKit_AI_Form_Processor; if (!defined('ABSPATH')) { exit; } class AIPKit_AI_Form_Initializer { public static function register_hooks() { if (class_exists(AIPKit_AI_Form_Admin_Setup::class)) { $admin_setup = new AIPKit_AI_Form_Admin_Setup(); add_action('init', [$admin_setup, 'register_cpt']); } if (class_exists(AIPKit_AI_Form_Shortcode::class)) { $shortcode_handler = new AIPKit_AI_Form_Shortcode(); add_shortcode('aipkit_ai_form', [$shortcode_handler, 'render_shortcode']); } if (!wp_doing_ajax()) { return; } if (class_exists(AIPKit_AI_Form_Processor::class)) { $form_processor = new AIPKit_AI_Form_Processor(); add_action('wp_ajax_aipkit_ai_form_upload_and_parse_file', [$form_processor, 'ajax_upload_and_parse_file']); add_action('wp_ajax_nopriv_aipkit_ai_form_upload_and_parse_file', [$form_processor, 'ajax_upload_and_parse_file']); add_action('wp_ajax_aipkit_ai_form_save_as_post', [$form_processor, 'ajax_save_as_post']); } } } 